import requests

def get_papers_with_code(task='image-classification', limit=5):
    """Fetch latest papers with implementations for a task"""
    url = f'https://paperswithcode.com/api/v1/papers?task={task}&s=new&limit={limit}'
    response = requests.get(url)

    if response.status_code == 200:
        data = response.json()
        return [
            {
                'title': p['title'],
                'url': p['url'],
                'year': p.get('year'),
                'code_url': p.get('code_url'),
                'datasets': p.get('datasets', [])
            }
            for p in data.get('results', [])
        ]
    return []

def get_sota_results(task='image-classification'):
    """Get state-of-the-art results for a task"""
    url = f'https://paperswithcode.com/api/v1/sota?task={task}'
    response = requests.get(url)

    if response.status_code == 200:
        return response.json()
    return None
